int popcount_depth(long long x) {
    if (x == 1) return 0;
    int depth = 0;
    while (x != 1) {
        x = __builtin_popcountll(x);
        depth++;
    }
    return depth;
}

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    unordered_map<long long, int> depth_cache;
    vector<int> depths(nums.size());
    for (int i = 0; i < nums.size(); ++i) {
        long long num = nums[i];
        if (depth_cache.find(num) == depth_cache.end()) {
            depth_cache[num] = popcount_depth(num);
        }
