import java.util.HashMap;

public class Solution {
    private static int popcountDepth(long x) {
        if (x == 1) return 0;
        int depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }

    public static long[] solve(long[] nums, long[][] queries) {
        HashMap<Long, Integer> depthCache = new HashMap<>();
        int[] depths = new int[nums.length];
        for (int i = 0; i < nums.length; ++i) {
            long num = nums[i];
            if (!depthCache.containsKey(num)) {
                depthCache.put(num, popcountDepth(num));
            }
            depths[i] = depthCache.get(num);
        }

        int answerCount = 0;
        for (long[] query : queries) {
            if (query[0] == 1) {
                answerCount++;
            }
        }

        long[] answer = new long[answerCount];
        int answerIdx = 0;
        for (long[] query : queries) {
            if (query[0] == 1) {
                int l = (int) query[1];
                int r = (int) query[2];
                int k = (int) query[3];
                int count = 0;
                for (int i = l; i <= r; ++i) {
                    if (depths[i] == k) {
                        count++;
