                int idx = (int) query[1];
                long val = query[2];
                nums[idx] = val;
                if (!depthCache.containsKey(val)) {
                    depthCache.put(val, popcountDepth(val));
                }
                depths[idx] = depthCache.get(val);
            }
        }
        return answer;
    }
}
